&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Refer&lt;/strong&gt; is commonly used in business and formal communication to direct someone to a specific document or previous correspondence.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;It helps provide context or background for the current communication.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

questions.statement:
Select the option that expresses the given sentence in indirect voice.&lt;br /&gt;
&lt;br /&gt;
The teacher said to the students, &amp;quot;If you complete your projects on time, I will consider giving you extra marks.&amp;quot;

questions.explanation:
&lt;div&gt;&lt;span style=&quot;&quot;&gt;The correct answer is &lt;strong&gt;Option 1&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Indirect Speech:&lt;/strong&gt; The teacher told the students that if they completed their projects on time, she would consider giving them extra marks.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Key Conversions:&lt;/strong&gt;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;&amp;quot;if they completed their projects&amp;quot; replaces &amp;quot;if you complete your projects&amp;quot;&lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;Pronoun &amp;quot;you&amp;quot; is changed to &amp;quot;they&amp;quot; to match indirect speech.&lt;/li&gt;
			&lt;li&gt;Verb &amp;quot;complete&amp;quot; is changed to &amp;quot;completed&amp;quot; to reflect past tense in indirect speech.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&amp;quot;she would consider giving them&amp;quot; replaces &amp;quot;I will consider giving you&amp;quot;&lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;Pronoun &amp;quot;I&amp;quot; is changed to &amp;quot;she&amp;quot; to match the speaker.&lt;/li&gt;
			&lt;li&gt;Verb &amp;quot;will&amp;quot; is changed to &amp;quot;would&amp;quot; to match indirect speech.&lt;/li&gt;
			&lt;li&gt;Pronoun &amp;quot;you&amp;quot; is changed to &amp;quot;them&amp;quot; to match indirect speech.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Punctuation and Format:&lt;/strong&gt;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;Direct speech is converted into a reported clause.&lt;/li&gt;
		&lt;li&gt;No quotation marks are used in indirect speech.&lt;/li&gt;
		&lt;li&gt;The sentence structure is adjusted to ensure grammatical accuracy.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;Therefore, the correct answer is &lt;strong&gt;Option 1&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Correct Sentence:&lt;/strong&gt; &lt;em&gt;The teacher told the students that if they completed their projects on time, she would consider giving them extra marks.&lt;/em&gt;&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Option 2:&lt;/strong&gt; The teacher told the students that if they complete their projects on time, she will consider giving them extra marks.&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;Incorrect tense usage: &amp;quot;complete&amp;quot; and &amp;quot;will&amp;quot; do not reflect past tense required in indirect speech.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Option 3:&lt;/strong&gt; The teacher told the students that if they completed their projects on time, she will consider giving them extra marks.&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;Incorrect tense usage: &amp;quot;will&amp;quot; should be &amp;quot;would&amp;quot; in indirect speech.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Option 4:&lt;/strong&gt; The teacher told the students that if they complete their projects on time, she would consider giving them extra marks.&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;Incorrect tense usage: &amp;quot;complete&amp;quot; should be &amp;quot;completed&amp;quot; in indirect speech.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

The correct answer is&lt;strong&gt;- &amp;#39;Forced&amp;#39;&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;let&amp;#39;s look at the meaning of the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;given word&lt;/span&gt;&amp;nbsp;and the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;correct answer.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Unwilling&lt;/strong&gt;(adjective): not willing. (सहमत नहीं।)
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;color: rgb(48, 51, 54); font-variant-ligatures: no-common-ligatures; letter-spacing: 0.2px;&quot;&gt;​&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example&lt;/span&gt;&lt;span style=&quot;color: rgb(48, 51, 54); font-variant-ligatures: no-common-ligatures; letter-spacing: 0.2px;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;:&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;em&gt;an &lt;strong&gt;unwilling&lt;/strong&gt; helper.&lt;/em&gt;&lt;span style=&quot;color: rgb(48, 51, 54); font-variant-ligatures: no-common-ligatures; letter-spacing: 0.2px;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;Forced&lt;/span&gt;(&lt;span style=&quot;&quot;&gt;adjective&lt;/span&gt;)&lt;span style=&quot;color: rgb(32, 33, 36);&quot;&gt;:&lt;/span&gt;&amp;nbsp;done against your wishes, or because it is suddenly made necessary by an unexpected situation. (आपकी इच्छा के विरुद्ध किया गया है, या क्योंकि यह किसी अप्रत्याशित स्थिति से अचानक आवश्यक हो गया है।)
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&amp;nbsp;&lt;/span&gt;&lt;em&gt;The plane had to make a &lt;strong&gt;forced &lt;/strong&gt;landing because one of the engines failed.​&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/em&gt;&lt;br /&gt;
		&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;Hence, the word&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Forced&amp;nbsp;&lt;/span&gt;is the most appropriate synonym&amp;nbsp;for&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Unwilling.&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;Let&amp;#39;s explore the meaning of other options&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Intentional&lt;/span&gt;&lt;/strong&gt;(verb):&amp;nbsp;to have as a plan or purpose. (एक योजना या उद्देश्य के रूप में होना।)
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&amp;nbsp;&lt;/span&gt;&lt;em&gt;We &lt;strong&gt;intend &lt;/strong&gt;to go to Australia next year.​&lt;/em&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Willing&lt;/span&gt;&lt;/strong&gt;(adjective): A willing person does their work energetically and enthusiastically. (एक इच्छुक व्यक्ति अपने काम को ऊर्जावान और उत्साह से करता है।)
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&lt;/span&gt;&lt;em&gt;&amp;nbsp;a &lt;strong&gt;willing&lt;/strong&gt; helper.&lt;/em&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Freewill&lt;/span&gt;&lt;/strong&gt;(noun): the ability to decide what to do independently of any outside influence. (किसी भी बाहरी प्रभाव से स्वतंत्र रूप से क्या करना है, यह तय करने की क्षमता।)
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Example:&amp;nbsp;&lt;/span&gt;&lt;em&gt;No one told me to do it - I did it of my own&lt;strong&gt; free will&lt;/strong&gt;.&lt;/em&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;The correct answer is &lt;strong&gt;&amp;#39;enhance&amp;#39;&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The passage explains how modern machinery and scientific techniques have improved agricultural practices and helped farmers produce more food.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The sentence states that farmers are now able to ______ productivity and meet growing food demands.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;quot;Enhance&amp;quot;&lt;/strong&gt; means to increase, improve, or strengthen something, which fits logically with increasing agricultural productivity.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;Therefore, the sentence correctly reads: farmers are now able to &lt;strong&gt;enhance productivity&lt;/strong&gt; and meet growing food demands.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;Therefore, the correct answer is &lt;strong&gt;Option 3&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Reduce (कम करना):&lt;/strong&gt; means to make something smaller or less in amount. It does not fit because the passage talks about increasing productivity.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Ignore (अनदेखा करना):&lt;/strong&gt; means to deliberately pay no attention to something. It is irrelevant in the context of improving farming output.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Abandon (त्याग देना):&lt;/strong&gt; means to leave or give up something completely. This contradicts the idea of improving agricultural productivity.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;The correct answer is &lt;strong&gt;&amp;#39;Option 1&amp;#39;&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The passage discusses modern developments in agriculture, particularly the introduction of high-yield variety seeds.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The sentence states that these seeds are designed to ______ resistance to pests and adverse weather conditions.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The verb &lt;strong&gt;&amp;quot;provide&amp;quot;&lt;/strong&gt; correctly fits the context because high-yield seeds are developed to &lt;strong&gt;provide resistance&lt;/strong&gt; against pests and harsh environmental conditions.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The phrase &lt;strong&gt;&amp;quot;provide resistance&amp;quot;&lt;/strong&gt; is a commonly used and grammatically correct collocation in agricultural and scientific contexts.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;Therefore, the correct answer is &lt;strong&gt;&amp;#39;Option 1&amp;#39;&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Decrease (कम करना):&lt;/strong&gt; It means to reduce something. It does not fit the context because seeds do not decrease resistance; they provide or increase it.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Prevent (रोकना):&lt;/strong&gt; It means to stop something from happening. Grammatically it does not collocate with &amp;ldquo;resistance&amp;rdquo; in this context.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Eliminate (समाप्त करना):&lt;/strong&gt; It means to completely remove something. It is inappropriate here because the sentence talks about giving resistance, not removing it.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;The correct answer is &lt;strong&gt;&amp;#39;Option 4&amp;#39;&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The passage discusses how modern agricultural techniques such as fertilizers and soil testing help farmers enhance crop production.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The sentence states that fertilizers and soil testing methods help farmers ______ the quality of crops.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The word &lt;strong&gt;&amp;quot;improve&amp;quot;&lt;/strong&gt; fits correctly because it means to make something better or enhance its quality.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;Thus, fertilizers and soil testing help farmers &lt;strong&gt;improve the quality of crops&lt;/strong&gt;, which matches the context of increased agricultural productivity.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;Therefore, the correct answer is &lt;strong&gt;&amp;#39;Option 4&amp;#39;&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Deteriorate (बिगाड़ना):&lt;/strong&gt; It means to become worse or decline in quality, which is opposite to the intended meaning in the passage.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Weaken (कमज़ोर करना):&lt;/strong&gt; It means to make something less strong or effective; this does not suit the context of enhancing crop quality.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Divide (विभाजित करना):&lt;/strong&gt; It means to separate something into parts, which is unrelated to improving crop quality.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;The correct answer is &lt;strong&gt;Option 2&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The sentence states that mobile applications provide real-time weather forecasts and market prices to farmers.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;This information helps farmers &lt;strong&gt;make informed decisions&lt;/strong&gt; about sowing crops and selling their produce.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The verb &lt;strong&gt;&amp;quot;make&amp;quot;&lt;/strong&gt; correctly forms the common collocation &lt;strong&gt;&amp;quot;make informed decisions&amp;quot;&lt;/strong&gt;, which means taking decisions based on accurate information.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;Other options do not logically fit the context of using digital information for decision-making.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;Therefore, the correct answer is &lt;strong&gt;Option 2&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Postpone (स्थगित करना):&lt;/strong&gt; to delay or arrange something to take place at a later time.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Neglect (उपेक्षा करना):&lt;/strong&gt; to fail to care for something properly or ignore it.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;Guess (अनुमान लगाना):&lt;/strong&gt; to form an opinion or estimate without sufficient information.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;The correct answer is &lt;strong&gt;&amp;#39;Option 2&amp;#39;&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The passage discusses advancements in agriculture such as modern machinery, high-yield seeds, fertilizers, and digital platforms that help farmers improve productivity.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The sentence states that &lt;strong&gt;government schemes aim to ______ sustainable farming practices by offering subsidies and training programs.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The word &lt;strong&gt;&amp;quot;promote&amp;quot;&lt;/strong&gt; means to encourage or support the growth or development of something.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;Since subsidies and training programs are intended to encourage farmers to adopt sustainable practices, &lt;strong&gt;&amp;quot;promote&amp;quot;&lt;/strong&gt; fits the context logically and grammatically.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;Therefore, the correct answer is &lt;strong&gt;&amp;#39;Option 2&amp;#39;&lt;/strong&gt;.&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;

&lt;ul&gt;
